{
    "level": "A1–A2",
    "intro": "In this topic, you will learn <strong>Yes/No Questions</strong> - the simplest type of question in the English language that can be answered with "yes" or "no".",
    "rules": [
        {
            "label": "With DO/DOES/DID",
            "color": "emerald",
            "text": "<strong>Auxiliary verb</strong> before the subject:",
            "example": "Do you like coffee? Does she work here?"
        },
        {
            "label": "With TO BE",
            "color": "blue",
            "text": "<strong>Inversion</strong> is a verb before the subject:",
            "example": "Are you ready? Is he a teacher?"
        },
        {
            "label": "WITH MODALS",
            "color": "amber",
            "text": "<strong>Modal verb</strong> before the subject:",
            "example": "Can you swim? Should we go?"
        }
    ]
}

{
    "title": "1. What are general questions?",
    "intro": "Yes/No Questions (general questions) are questions to which you can answer "yes" or "no":",
    "items": [
        {
            "label": "Question",
            "title": "Do you like tea?",
            "subtitle": "Do you like tea?"
        },
        {
            "label": "Answer Yes, I do. General questions with DO/DOES/DID",
            "title": "Yes, I do.",
            "subtitle": "Так (подобається)."
        },
        {
            "label": "Відповідь "Ні"",
            "title": "No, I don't.",
            "subtitle": "Ні (не подобається)."
        }
    ]
}

{
    "title": "2. Загальні питання з DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple — DO/DOES",
            "color": "emerald",
            "description": "In <strong>Present Simple</strong> we use <strong>do</strong> (with I, you, we, they) or <strong>does</strong> (with he, she, it).",
            "examples": [
                {
                    "en": "Do you speak English?",
                    "ua": "Do you speak English?"
                },
                {
                    "en": "Do they live in Kyiv?",
                    "ua": "They live in Kyiv?"
                },
                {
                    "en": "Does she work here?",
                    "ua": "She works here? working?"
                },
                {
                    "en": "Does it work?",
                    "ua": "Це працює?"
                }
            ]
        },
        {
            "label": "Past Simple - DID",
            "color": "sky",
            "description": "In <strong>Past Simple</strong> we use <strong>did</strong> with all persons. The main verb remains in its base form.",
            "examples": [
                {
                    "en": "Did you see the movie?",
                    "ua": "Did they arrive on time?"
                },
                {
                    "en": "Did she call you?",
                    "ua": "She called you?"
                },
                {
                    "en": " On time?",
                    "ua": "Did she call you?"
                },
                {
                    "en": "Did it rain yesterday? ...?",
                    "ua": "Вчора йшов дощ?"
                }
            ]
        },
        {
            "label": "Структура",
            "color": "purple",
            "description": "Формула загального питання з do/does/did:",
            "examples": [
                {
                    "en": "Do/Does/Did + Subject + Verb (base form) + ...?",
                    "ua": "Auxiliary + Subject + Verb + ...?"
                }
            ],
            "note": "📌 The main verb is always in the basic form (without -s, -ed)!"
        }
    ]
}

{
    "title": "3. General questions with TO BE",
    "sections": [
        {
            "label": "Present Simple — AM/IS/ARE",
            "color": "blue",
            "description": "With the verb <strong>to be</strong> in the Present Simple, we simply change the verb and the subject.",
            "examples": [
                {
                    "en": "Are you ready?",
                    "ua": "Are you ready?"
                },
                {
                    "en": "Is she a teacher?",
                    "ua": "She is a teacher?"
                },
                {
                    "en": "Are they at home?",
                    "ua": "They are at home?"
                },
                {
                    "en": "Is it expensive?",
                    "ua": "Is it expensive?"
                }
            ]
        },
        {
            "label": "Past Simple — WAS/WERE",
            "color": "amber",
            "description": "In Past Simple we use <strong>was</strong> (with I, he, she, it) or <strong>were</strong> (with you, we, they).",
            "examples": [
                {
                    "en": "Was he at work yesterday?",
                    "ua": "He was at work yesterday?"
                },
                {
                    "en": "Were you tired?",
                    "ua": "You were tired?"
                },
                {
                    "en": "Were they happy?",
                    "ua": "They were happy?"
                },
                {
                    "en": "Was it difficult?",
                    "ua": "It was difficult?"
                }
            ]
        },
        {
            "label": "Structure",
            "color": "rose",
            "description": "General question formula with to be:",
            "examples": [
                {
                    "en": "Am/Is/Are/Was/Were + Subject + ...?",
                    "ua": "Form to be + Subject + ...?"
                }
            ],
            "note": "📌 No need to add do/does/did with the verb to be!"
        }
    ]
}

{
    "title": "4. General Questions with Modal Verbs swim? ",
    "sections": [
        {
            "label": "CAN / COULD",
            "color": "emerald",
            "description": "З <strong>can/could</strong> (можу/міг би) ставимо модальне дієслово перед підметом.",
            "examples": [
                {
                    "en": "Can you swim?",
                    "ua": "Ти вмієш плавати?"
                },
                {
                    "en": "Can she drive?",
                    "ua": "She can drive? come?"
                },
                {
                    "en": "Could you help me?",
                    "ua": "Ти міг би мені допомогти?"
                },
                {
                    "en": "Could they come?",
                    "ua": "Вони змогли прийти?"
                }
            ]
        },
        {
            "label": "WILL / WOULD",
            "color": "sky",
            "description": "With <strong>will/would</strong> (I will/would) we also put the modal in front of the subject.",
            "examples": [
                {
                    "en": "Will you come?",
                    "ua": "You come?"
                },
                {
                    "en": "Will it rain?",
                    "ua": "Will it rain?"
                },
                {
                    "en": "Would you like coffee?",
                    "ua": "Should / MUST / MAY"
                },
                {
                    "en": "Would she agree?",
                    "ua": "Вона б погодилась?"
                }
            ]
        },
        {
            "label": "SHOULD / MUST / MAY",
            "color": "purple",
            "description": "Інші модальні дієслова працюють за тим самим принципом.",
            "examples": [
                {
                    "en": "Should we go?",
                    "ua": "Нам варто піти?"
                },
                {
                    "en": "Must I wait?",
                    "ua": "Я мушу чекати?"
                },
                {
                    "en": "May I ask?",
                    "ua": "May I ask?"
                }
            ],
            "note": "📌 Structure: Modal + Subject + Verb (base form) + ...?"
        }
    ]
}

{
    "title": "5. General questions with HAVE GOT",
    "sections": [
        {
            "label": "HAVE GOT / HAS GOT",
            "color": "blue",
            "description": "With <strong>have got</strong> (have) we make an inversion — we put have/has before the subject.",
            "examples": [
                {
                    "en": "Have you got a car?",
                    "ua": "Do you have a car?"
                },
                {
                    "en": "Has she got have a dog? do/does.",
                    "ua": "У неї є собака?"
                },
                {
                    "en": "Have they got time?",
                    "ua": "У них є час?"
                }
            ]
        },
        {
            "label": "HAVE / HAS (володіння)",
            "color": "amber",
            "description": "У американському варіанті з <strong>have</strong> як основним дієсловом використовуємо do/does.",
            "examples": [
                {
                    "en": "Do you have a car?",
                    "ua": "Does she have a dog?"
                },
                {
                    "en": "Does she have a dog?",
                    "ua": "Do they have time?"
                },
                {
                    "en": "Do they have time?",
                    "ua": "They have Time? Other tenses"
                }
            ],
            "note": "📌 У британському варіанті частіше have got, у американському — have з do/does."
        }
    ]
}

{
    "title": "6. Інші часи",
    "sections": [
        {
            "label": "Present Continuous",
            "color": "emerald",
            "description": "With <strong>Present Continuous</strong> (am/is/are + Ving) we make am/is/are inversion.",
            "examples": [
                {
                    "en": "Are you working now?",
                    "ua": "Are you working now?"
                },
                {
                    "en": "Is she coming?",
                    "ua": "She is coming?"
                },
                {
                    "en": "Are they playing?",
                    "ua": "They are playing?"
                }
            ]
        },
        {
            "label": "Present Perfect",
            "color": "sky",
            "description": "With the <strong>Present Perfect</strong> (have/has + V3) we make the have/has inversion.",
            "examples": [
                {
                    "en": "Have you seen this movie?",
                    "ua": "Have you seen this movie?"
                },
                {
                    "en": "Has she finished?",
                    "ua": "Have they finished?"
                },
                {
                    "en": "Have they came? she studying?",
                    "ua": "Вони приїхали?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "purple",
            "description": "З <strong>Past Continuous</strong> (was/were + Ving) робимо інверсію was/were.",
            "examples": [
                {
                    "en": "Were you sleeping?",
                    "ua": "Ти спав?"
                },
                {
                    "en": "Was she studying?",
                    "ua": "She studied?[[(CODX_SEG_13]]]Were they watching TV? Comparison table"
                },
                {
                    "en": "Were they watching TV?",
                    "ua": "Вони дивилися телевізор?"
                }
            ],
            "note": "📌 Загальне правило: допоміжне дієслово виноситься перед підмет."
        }
    ]
}

{
    "title": "7. Порівняльна таблиця",
    "intro": "How to form general questions with different types of verbs:",
    "rows": [
        {
            "en": "Simple (do/does/did)",
            "ua": "Simple tenses",
            "note": "Do you like...? Does she work...? Did they come...?"
        },
        {
            "en": "To be (am/is/are/was/were)",
            "ua": "Verb to be",
            "note": "Are you ready? Is she here? Were they happy?"
        },
        {
            "en": "Modals (can/will/should...)",
            "ua": "Modal verbs",
            "note": "Can you swim? Will you come? Should we go?"
        },
        {
            "en": "Have got",
            "ua": "Mother (have got)",
            "note": "Have you got...? Has she got...?"
        },
        {
            "en": "Continuous (am/is/are + Ving)",
            "ua": "Continuous times",
            "note": "Are you working? Was she sleeping?"
        },
        {
            "en": "Perfect (have/has + V3)",
            "ua": "Perfect times",
            "note": "Have you seen...? Has she finished...?"
        }
    ],
    "warning": "📌 Basic principle: <strong>auxiliary verb before the subject</strong>!"
}

{
    "title": "8. Typical mistakes",
    "items": [
        {
            "label": "Error 1",
            "color": "rose",
            "title": "Incorrect word order - the subject before the verb.",
            "wrong": "❌ You are ready? You can swim?",
            "right": " ✅ <span class="font-mono">Are you ready? Can you swim?</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Using do/does/did with to be.",
            "wrong": "❌ Do you are happy? Did you were there?",
            "right": " ✅ <span class="font-mono">Are you happy? Were you there?</span>"
        },
        {
            "label": "Error 3",
            "color": "sky",
            "title": "Incorrect form of the main verb.",
            "wrong": "❌ Does she works? Did they go?",
            "right": "​​​​ <span class="font-mono">Does she work? Did they go?</span>"
        },
        {
            "label": "Error 4",
            "color": "purple",
            "title": "Omission of auxiliary verb.",
            "wrong": "❌ You like coffee? She works here?",
            "right": "​​​​ <span class="font-mono">Do you like coffee? Does she work here?</span>"
        }
    ]
}

{
    "title": "10. Practice",
    "select_title": "Exercise 1. Choose the correct option",
    "select_intro": "Choose the correct form of a general question.",
    "selects": [
        {
            "label": "a) Do you like coffee? / b) Do you like coffee? / c) You do like coffee?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Is she ready? / b) Is she ready? / c) She is ready?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Can you swim? / b) Can you swim? / c) You can swim?",
            "prompt": "Which option is correct?"
        },
        {
            "label": "a) Did they go? / b) Did they go? / c) They did went? sentence.",
            "prompt": "Який варіант правильний?"
        }
    ],
    "options": [
        "a",
        "b",
        "c"
    ],
    "input_title": "Вправа 2. Постав питання",
    "input_intro": "Утвори загальне питання з поданого речення.",
    "inputs": [
        {
            "before": "She likes tea. → ",
            "after": ""
        },
        {
            "before": "They are happy. → ",
            "after": ""
        },
        {
            "before": "He can dance. → ",
            "after": ""
        },
        {
            "before": "You have a car. → ",
            "after": ""
        }
    ],
    "rephrase_title": "Exercise 3. Correct the error",
    "rephrase_intro": "Find and correct the error in the question.",
    "rephrase": [
        {
            "example_label": "Example:",
            "example_original": "You are ready?",
            "example_target": "Are you ready?"
        },
        {
            "original": "1. Does she is happy?",
            "placeholder": "Fix the error"
        },
        {
            "original": "2. Did they go home?",
            "placeholder": "Fix the error"
        },
        {
            "original": "3. You can help me?",
            "placeholder": "Correct the error"
        }
    ]
}

